import json
with open('baseline-packages.json') as f: before = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def get_pkgs(data):
    result = {}
    for proj in data.get('projects', []):
        pname = proj['path'].split('/')[-1]
        pkgs = {}
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                pkgs[pkg['id']] = pkg.get('resolvedVersion', pkg.get('requestedVersion',''))
        result[pname] = pkgs
    return result

b = get_pkgs(before)
a = get_pkgs(after)
changes = []
unchanged = []
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(pkg)
        av = ap.get(pkg)
        if bv != av:
            changes.append((proj, pkg, bv or 'N/A', av or 'N/A'))
        else:
            unchanged.append((proj, pkg, bv))

print('=== CHANGES ===')
for c in changes:
    print(f'{c[0]}: {c[1]} {c[2]} -> {c[3]}')
print(f'Total changes: {len(changes)}')
print()
print(f'=== UNCHANGED: {len(unchanged)} packages ===')
"

